// Read all demo transcript filenames
// In production: scan /transcripts/demo/ directory
const accounts = [
  { file: 'demo_001.txt', account_id: 'ACE_001' },
  { file: 'demo_002.txt', account_id: 'BSE_002' },
  { file: 'demo_003.txt', account_id: 'GCR_003' },
  { file: 'demo_004.txt', account_id: 'NHS_004' },
  { file: 'demo_005.txt', account_id: 'RRR_005' },
];
return accounts.map(a => ({ json: a }));

// Reads transcript file from filesystem
// In n8n self-hosted: use filesystem or HTTP request node
const { file, account_id } = $input.item.json;
// Simulate reading file content
return [{ json: { account_id, file, transcript: `[Content of ${file}]`, status: 'loaded' } }];

// Parse LLM response and extract JSON
const response = $input.item.json;
const content = response.choices[0].message.content;
let memo;
try {
  const clean = content.replace(/```json/g,'').replace(/```/g,'').trim();
  memo = JSON.parse(clean);
} catch(e) {
  memo = { error: 'parse_failed', raw: content.substring(0,500) };
}
return [{ json: { ...memo, _raw_input: $input.item.json } }];

// Save outputs to filesystem
// In n8n self-hosted: use Write Binary File or HTTP node to your storage
const memo = $input.item.json;
const accountId = memo.account_id || 'UNKNOWN';
console.log(`Saving v1 outputs for ${accountId}`);
// Create task tracker item
const task = {
  task_id: `TASK-${accountId}-V1`,
  title: `[V1] Agent configured for ${memo.company_name}`,
  account_id: accountId,
  status: 'ready_for_review',
  version: 'v1',
  created_at: new Date().toISOString()
};
return [{ json: { status: 'saved', account_id: accountId, task } }];

const onboardingFiles = [
  { file: 'onboarding_001.txt', account_id: 'ACE_001' },
  { file: 'onboarding_002.txt', account_id: 'BSE_002' },
  { file: 'onboarding_003.txt', account_id: 'GCR_003' },
  { file: 'onboarding_004.txt', account_id: 'NHS_004' },
  { file: 'onboarding_005.txt', account_id: 'RRR_005' },
];
return onboardingFiles.map(f => ({ json: f }));

// Load v1 memo from storage + onboarding transcript
const { file, account_id } = $input.item.json;
// In production: read from outputs/accounts/{account_id}/v1/account_memo.json
return [{ json: { account_id, onboarding_file: file, v1_memo: {}, onboarding_transcript: `[Content of ${file}]` } }];

// Apply patch + generate changelog
const updates = $input.item.json;
console.log('Applying v1 -> v2 patch...');
const changelog = {
  version_from: 'v1',
  version_to: 'v2',
  generated_at: new Date().toISOString(),
  changes: updates.choices?.[0]?.message?.content || 'See raw updates'
};
return [{ json: { status: 'patched', changelog } }];

// Save v2 outputs
console.log('Saving v2 outputs...');
return [{ json: { status: 'complete', version: 'v2', saved_at: new Date().toISOString() } }];
